package com.taskflow.repository;

import com.taskflow.entity.User;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.orm.jpa.DataJpaTest;
import org.springframework.boot.test.autoconfigure.orm.jpa.TestEntityManager;
import org.springframework.test.context.ActiveProfiles;

import java.util.Optional;

import static org.assertj.core.api.Assertions.assertThat;

/**
 * Tests for UserRepository custom query methods.
 *
 * Covers:
 * - findByUsername: happy path, not found, case sensitivity
 */
@DataJpaTest
@ActiveProfiles("test")
@DisplayName("UserRepository Tests")
class UserRepositoryTest {

    @Autowired
    private UserRepository userRepository;

    @Autowired
    private TestEntityManager entityManager;

    private User savedUser;

    @BeforeEach
    void setUp() {
        User user = new User();
        user.setUsername("john_doe");
        user.setPassword("hashed_password");
        user.setDisplayName("John Doe");
        savedUser = entityManager.persistFlushFind(user);
    }

    @Test
    @DisplayName("should find user by username when user exists")
    void shouldFindUserByUsernameWhenUserExists() {
        Optional<User> found = userRepository.findByUsername("john_doe");

        assertThat(found).isPresent();
        assertThat(found.get().getUsername()).isEqualTo("john_doe");
        assertThat(found.get().getDisplayName()).isEqualTo("John Doe");
        assertThat(found.get().getId()).isEqualTo(savedUser.getId());
    }

    @Test
    @DisplayName("should return empty when username does not exist")
    void shouldReturnEmptyWhenUsernameDoesNotExist() {
        Optional<User> found = userRepository.findByUsername("nonexistent");

        assertThat(found).isEmpty();
    }

    @Test
    @DisplayName("should return empty when username is null")
    void shouldReturnEmptyWhenUsernameIsNull() {
        Optional<User> found = userRepository.findByUsername(null);

        assertThat(found).isEmpty();
    }

    @Test
    @DisplayName("should find correct user among multiple users")
    void shouldFindCorrectUserAmongMultipleUsers() {
        User user2 = new User();
        user2.setUsername("jane_doe");
        user2.setPassword("another_hash");
        user2.setDisplayName("Jane Doe");
        entityManager.persistAndFlush(user2);

        Optional<User> found = userRepository.findByUsername("jane_doe");

        assertThat(found).isPresent();
        assertThat(found.get().getUsername()).isEqualTo("jane_doe");
        assertThat(found.get().getDisplayName()).isEqualTo("Jane Doe");
    }
}

