package com.taskflow.security;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.assertThatThrownBy;

/**
 * Unit tests for JwtTokenProvider.
 *
 * No Spring context needed — instantiate directly with constructor args.
 * Expected constructor: JwtTokenProvider(String secret, long expirationMs)
 *
 * Covers:
 * - Token generation: contains userId claim, is non-empty
 * - Token parsing: extract userId from valid token
 * - Token validation: valid token returns true
 * - Expired token detection
 * - Malformed/invalid token handling
 * - Null/empty token handling
 */
@DisplayName("JwtTokenProvider Unit Tests")
class JwtTokenProviderTest {

    private static final String SECRET = "test-jwt-secret-key-must-be-at-least-256-bits-long-for-HS256";
    private static final long EXPIRATION_MS = 86400000L; // 24 hours
    private static final long SHORT_EXPIRATION_MS = 1L; // 1ms for expiry tests

    private JwtTokenProvider tokenProvider;

    @BeforeEach
    void setUp() {
        tokenProvider = new JwtTokenProvider(SECRET, EXPIRATION_MS);
    }

    @Nested
    @DisplayName("Token Generation")
    class TokenGeneration {

        @Test
        @DisplayName("should generate non-empty token for valid userId")
        void shouldGenerateNonEmptyTokenForValidUserId() {
            String token = tokenProvider.generateToken(1L);

            assertThat(token).isNotNull().isNotEmpty();
        }

        @Test
        @DisplayName("should generate different tokens for different userIds")
        void shouldGenerateDifferentTokensForDifferentUserIds() {
            String token1 = tokenProvider.generateToken(1L);
            String token2 = tokenProvider.generateToken(2L);

            assertThat(token1).isNotEqualTo(token2);
        }

        @Test
        @DisplayName("should generate token that contains three parts separated by dots")
        void shouldGenerateTokenWithThreePartsJwtFormat() {
            String token = tokenProvider.generateToken(1L);

            String[] parts = token.split("\\.");
            assertThat(parts).hasSize(3); // header.payload.signature
        }
    }

    @Nested
    @DisplayName("Token Parsing")
    class TokenParsing {

        @Test
        @DisplayName("should extract userId from valid token")
        void shouldExtractUserIdFromValidToken() {
            Long userId = 42L;
            String token = tokenProvider.generateToken(userId);

            Long extractedId = tokenProvider.getUserIdFromToken(token);

            assertThat(extractedId).isEqualTo(userId);
        }

        @Test
        @DisplayName("should extract correct userId for different users")
        void shouldExtractCorrectUserIdForDifferentUsers() {
            String token1 = tokenProvider.generateToken(1L);
            String token2 = tokenProvider.generateToken(999L);

            assertThat(tokenProvider.getUserIdFromToken(token1)).isEqualTo(1L);
            assertThat(tokenProvider.getUserIdFromToken(token2)).isEqualTo(999L);
        }
    }

    @Nested
    @DisplayName("Token Validation")
    class TokenValidation {

        @Test
        @DisplayName("should return true for valid non-expired token")
        void shouldReturnTrueForValidNonExpiredToken() {
            String token = tokenProvider.generateToken(1L);

            boolean isValid = tokenProvider.validateToken(token);

            assertThat(isValid).isTrue();
        }

        @Test
        @DisplayName("should return false for expired token")
        void shouldReturnFalseForExpiredToken() throws InterruptedException {
            JwtTokenProvider shortLivedProvider = new JwtTokenProvider(SECRET, SHORT_EXPIRATION_MS);
            String token = shortLivedProvider.generateToken(1L);

            // Wait for token to expire
            Thread.sleep(50);

            boolean isValid = shortLivedProvider.validateToken(token);

            assertThat(isValid).isFalse();
        }

        @Test
        @DisplayName("should return false for malformed token")
        void shouldReturnFalseForMalformedToken() {
            boolean isValid = tokenProvider.validateToken("not.a.valid.jwt.token");

            assertThat(isValid).isFalse();
        }

        @Test
        @DisplayName("should return false for empty token")
        void shouldReturnFalseForEmptyToken() {
            boolean isValid = tokenProvider.validateToken("");

            assertThat(isValid).isFalse();
        }

        @Test
        @DisplayName("should return false for null token")
        void shouldReturnFalseForNullToken() {
            boolean isValid = tokenProvider.validateToken(null);

            assertThat(isValid).isFalse();
        }

        @Test
        @DisplayName("should return false for token with tampered signature")
        void shouldReturnFalseForTamperedToken() {
            String token = tokenProvider.generateToken(1L);
            // Tamper with the last character of the signature
            String tampered = token.substring(0, token.length() - 1) + (token.endsWith("A") ? "B" : "A");

            boolean isValid = tokenProvider.validateToken(tampered);

            assertThat(isValid).isFalse();
        }

        @Test
        @DisplayName("should return false for token signed with different secret")
        void shouldReturnFalseForTokenSignedWithDifferentSecret() {
            JwtTokenProvider otherProvider = new JwtTokenProvider(
                    "different-secret-key-must-also-be-long-enough-for-HS256-algo",
                    EXPIRATION_MS
            );
            String token = otherProvider.generateToken(1L);

            boolean isValid = tokenProvider.validateToken(token);

            assertThat(isValid).isFalse();
        }

        @Test
        @DisplayName("should return false for random string")
        void shouldReturnFalseForRandomString() {
            boolean isValid = tokenProvider.validateToken("random-garbage-string");

            assertThat(isValid).isFalse();
        }
    }
}

