package com.taskflow.security;

import jakarta.servlet.FilterChain;
import jakarta.servlet.ServletException;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;
import org.springframework.mock.web.MockHttpServletRequest;
import org.springframework.mock.web.MockHttpServletResponse;
import org.springframework.security.core.context.SecurityContextHolder;

import java.io.IOException;

import static org.assertj.core.api.Assertions.assertThat;
import static org.mockito.Mockito.*;

/**
 * Mock-based unit tests for JwtAuthFilter.
 *
 * Tests the OncePerRequestFilter that:
 * - Extracts Bearer token from Authorization header
 * - Validates the token via JwtTokenProvider
 * - Sets SecurityContext authentication on valid token
 * - Passes through (no auth set) on missing/invalid token
 *
 * Uses MockHttpServletRequest/Response to simulate HTTP requests.
 */
@ExtendWith(MockitoExtension.class)
@DisplayName("JwtAuthFilter Unit Tests")
class JwtAuthFilterTest {

    @Mock
    private JwtTokenProvider tokenProvider;

    @Mock
    private FilterChain filterChain;

    private JwtAuthFilter jwtAuthFilter;
    private MockHttpServletRequest request;
    private MockHttpServletResponse response;

    @BeforeEach
    void setUp() {
        jwtAuthFilter = new JwtAuthFilter(tokenProvider);
        request = new MockHttpServletRequest();
        response = new MockHttpServletResponse();
        SecurityContextHolder.clearContext();
    }

    @Nested
    @DisplayName("Valid Token Scenarios")
    class ValidTokenScenarios {

        @Test
        @DisplayName("should set authentication in SecurityContext when valid Bearer token is provided")
        void shouldSetAuthenticationWhenValidBearerToken() throws ServletException, IOException {
            String token = "valid.jwt.token";
            request.addHeader("Authorization", "Bearer " + token);

            when(tokenProvider.validateToken(token)).thenReturn(true);
            when(tokenProvider.getUserIdFromToken(token)).thenReturn(42L);

            jwtAuthFilter.doFilterInternal(request, response, filterChain);

            assertThat(SecurityContextHolder.getContext().getAuthentication()).isNotNull();
            assertThat(SecurityContextHolder.getContext().getAuthentication().isAuthenticated()).isTrue();
            verify(filterChain).doFilter(request, response);
        }

        @Test
        @DisplayName("should extract userId and set it as principal when token is valid")
        void shouldExtractUserIdAndSetAsPrincipal() throws ServletException, IOException {
            String token = "valid.jwt.token";
            request.addHeader("Authorization", "Bearer " + token);

            when(tokenProvider.validateToken(token)).thenReturn(true);
            when(tokenProvider.getUserIdFromToken(token)).thenReturn(42L);

            jwtAuthFilter.doFilterInternal(request, response, filterChain);

            Object principal = SecurityContextHolder.getContext().getAuthentication().getPrincipal();
            // The principal should contain or be the userId (42L)
            assertThat(principal.toString()).contains("42");
        }
    }

    @Nested
    @DisplayName("Missing/Invalid Token Scenarios")
    class MissingInvalidTokenScenarios {

        @Test
        @DisplayName("should not set authentication when no Authorization header present")
        void shouldNotSetAuthWhenNoAuthorizationHeader() throws ServletException, IOException {
            // No Authorization header set on request

            jwtAuthFilter.doFilterInternal(request, response, filterChain);

            assertThat(SecurityContextHolder.getContext().getAuthentication()).isNull();
            verify(filterChain).doFilter(request, response);
        }

        @Test
        @DisplayName("should not set authentication when Authorization header has no Bearer prefix")
        void shouldNotSetAuthWhenNoBearerPrefix() throws ServletException, IOException {
            request.addHeader("Authorization", "Basic sometoken");

            jwtAuthFilter.doFilterInternal(request, response, filterChain);

            assertThat(SecurityContextHolder.getContext().getAuthentication()).isNull();
            verify(filterChain).doFilter(request, response);
        }

        @Test
        @DisplayName("should not set authentication when token is invalid")
        void shouldNotSetAuthWhenTokenIsInvalid() throws ServletException, IOException {
            String token = "invalid.jwt.token";
            request.addHeader("Authorization", "Bearer " + token);

            when(tokenProvider.validateToken(token)).thenReturn(false);

            jwtAuthFilter.doFilterInternal(request, response, filterChain);

            assertThat(SecurityContextHolder.getContext().getAuthentication()).isNull();
            verify(filterChain).doFilter(request, response);
        }

        @Test
        @DisplayName("should not set authentication when Authorization header is empty Bearer")
        void shouldNotSetAuthWhenBearerIsEmpty() throws ServletException, IOException {
            request.addHeader("Authorization", "Bearer ");

            jwtAuthFilter.doFilterInternal(request, response, filterChain);

            assertThat(SecurityContextHolder.getContext().getAuthentication()).isNull();
            verify(filterChain).doFilter(request, response);
        }

        @Test
        @DisplayName("should not set authentication when Authorization header is just 'Bearer'")
        void shouldNotSetAuthWhenBearerOnly() throws ServletException, IOException {
            request.addHeader("Authorization", "Bearer");

            jwtAuthFilter.doFilterInternal(request, response, filterChain);

            assertThat(SecurityContextHolder.getContext().getAuthentication()).isNull();
            verify(filterChain).doFilter(request, response);
        }
    }

    @Nested
    @DisplayName("Filter Chain Continuation")
    class FilterChainContinuation {

        @Test
        @DisplayName("should always continue filter chain regardless of token validity")
        void shouldAlwaysContinueFilterChain() throws ServletException, IOException {
            // Case 1: No header
            jwtAuthFilter.doFilterInternal(request, response, filterChain);
            verify(filterChain, times(1)).doFilter(request, response);

            // Case 2: Invalid token
            setUp();
            request.addHeader("Authorization", "Bearer invalid");
            when(tokenProvider.validateToken("invalid")).thenReturn(false);
            jwtAuthFilter.doFilterInternal(request, response, filterChain);
            verify(filterChain, times(1)).doFilter(request, response);
        }

        @Test
        @DisplayName("should not call getUserIdFromToken when token is invalid")
        void shouldNotCallGetUserIdWhenTokenInvalid() throws ServletException, IOException {
            String token = "invalid.token";
            request.addHeader("Authorization", "Bearer " + token);

            when(tokenProvider.validateToken(token)).thenReturn(false);

            jwtAuthFilter.doFilterInternal(request, response, filterChain);

            verify(tokenProvider, never()).getUserIdFromToken(any());
        }
    }
}

